static const uint16_t* flagForReg(const char* reg) {
  if (!reg || !reg[0]) return nullptr;
  for (int i = 0; REG_FLAGS[i].pfx; i++) {
    size_t len = strlen(REG_FLAGS[i].pfx);
    if (strncmp(reg, REG_FLAGS[i].pfx, len) == 0) return REG_FLAGS[i].data;
  }
  return nullptr;
}

static void drawFlag(Arduino_GFX* gfx, int16_t x, int16_t y, const uint16_t* data) {
  if (!data) return;
  for (uint8_t row = 0; row < FLAG_H; row++)
    for (uint8_t col = 0; col < FLAG_W; col++)
      gfx->drawPixel(x+col, y+row, (uint16_t)pgm_read_word(&data[row*FLAG_W+col]));
}
